import{_ as e,a as o}from"./IIIF_Import-DDUiYusn.js";import{_ as i,c as r,b as a,o as n}from"./app-RrIk7Rat.js";const s={};function l(g,t){return n(),r("div",null,t[0]||(t[0]=[a('<h1 id="importing-images" tabindex="-1"><a class="header-anchor" href="#importing-images"><span>Importing Images</span></a></h1><p>In the <strong>Cartographer App</strong>, there are two ways to import images:</p><ol><li><strong>From a local MEI file</strong> — the file references images hosted on a IIIF server.</li><li><strong>Directly from a IIIF server</strong> — by providing the IIIF manifest link.</li></ol><hr><h2 id="importing-via-from-local-mei-file" tabindex="-1"><a class="header-anchor" href="#importing-via-from-local-mei-file"><span>Importing via from local MEI file.</span></a></h2><p>Clicking the <strong>menu icon</strong> in the header opens a list of options.<br> Select <strong>“Upload MEI File”</strong> to import an MEI XML file.</p><ul><li>You can load the <strong>provided test dataset</strong> by clicking <strong>Load Test Data</strong>.</li><li>Or, you can click <strong>Choose File</strong> to open a file selection dialog and upload your own MEI file.</li><li>After choosing a file, click <strong>Load</strong> to complete the import.</li><li>If you don’t want to proceed, click <strong>Cancel</strong> to close the dialog.</li></ul><hr><h3 id="step-by-step" tabindex="-1"><a class="header-anchor" href="#step-by-step"><span>Step-by-Step</span></a></h3><ol><li>Click the <strong>menu button</strong> in the header.</li><li>Choose one of the following: <ul><li><strong>Load Test Data</strong> → imports the sample dataset provided with Cartographer.</li><li><strong>Choose File</strong> → opens a dialog where you can select a file from your computer.<br><img src="'+e+'" alt="Import image window"></li></ul></li><li>Click <strong>Import</strong> to import the file.</li><li>(Optional) Click <strong>Cancel</strong> to exit without importing.</li></ol><h2 id="importing-directly-from-a-iiif-server" tabindex="-1"><a class="header-anchor" href="#importing-directly-from-a-iiif-server"><span>Importing Directly from a IIIF Server</span></a></h2><p>Clicking the <strong>menu icon</strong> in the header opens a list of options.<br> Select <strong>“Import IIIF Manifest”</strong> to import images directly from a IIIF server.</p><hr><p>When you select <strong>Import IIIF Manifest</strong>, a dialog appears:</p><ul><li><strong>Get Test URI</strong> → load the provided test manifest URI.</li><li><strong>Paste Your URI</strong> → manually paste your own IIIF manifest URI into the input box.</li><li><strong>Import</strong> → confirm and load the images.</li><li><strong>Cancel</strong> → close the dialog without importing.</li></ul><hr><h3 id="step-by-step-1" tabindex="-1"><a class="header-anchor" href="#step-by-step-1"><span>Step-by-Step</span></a></h3><ol><li>Click the <strong>menu button</strong> in the header.</li><li>Choose one of the following: <ul><li><strong>Get Test URI</strong> → use the sample manifest provided with Cartographer.</li><li><strong>Paste Your URI</strong> → enter your own IIIF manifest URI in the input field.<br><img src="'+o+'" alt="Import IIIF Manifest"></li></ul></li><li>Click <strong>Import</strong> to load the images.</li><li>(Optional) Click <strong>Cancel</strong> to close the dialog without importing.</li></ol>',18)]))}const c=i(s,[["render",l]]),h=JSON.parse('{"path":"/user/ImportingImages.html","title":"Importing Images","lang":"en-US","frontmatter":{},"git":{"updatedTime":1756480448000,"contributors":[{"name":"Hizkiel","username":"Hizkiel","email":"hizclick@gmail.com","commits":2,"url":"https://github.com/Hizkiel"}],"changelog":[{"hash":"3e5c6e5adac83d3c5eef9ca1db6a3e4f00a4b3b1","time":1756480448000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Edit Dockerfile"},{"hash":"f154f171982bcbf31ca935ebf59603fd9f7ba544","time":1756211745000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Remove user documentation directory"}]},"filePathRelative":"user/ImportingImages.md"}');export{c as comp,h as data};
